<script setup lang="ts">
import GeneralTab from '~/components/product-edit/tabs/GeneralTab.vue'
import MembersAreaTab from '~/components/product-edit/tabs/MembersAreaTab.vue'
import SettingsTab from '~/components/product-edit/tabs/SettingsTab.vue'
import CheckoutBuilderTab from '~/components/product-edit/tabs/CheckoutBuilderTab.vue'
import CoproductionsTab from '~/components/product-edit/tabs/CoproductionsTab.vue'
import AffiliatesTab from '~/components/product-edit/tabs/AffiliatesTab.vue'
import LinksTab from '~/components/product-edit/tabs/LinksTab.vue'
import { uploadFile } from '~/utils/supabase'
import { paymentMethodsFromSetting } from '~/services/productsService'
useHead({ title: "Produto" })
useLegacyKiwifyInteractions()
const { complexFieldState } = useComplexFieldMocks()
const { getProductById, createProduct, updateProduct, deleteProduct } = useProducts()
const { productEditToggleState, applyProductEditToggleState } = useProductEditToggles()
const { showSuccessToast } = useKiwifyToast()
const route = useRoute()
const productId = computed(() => String(route.params.id || 'ae3c3610-f0af-11f0-b85d-45218e98c266'))
const isNewProduct = computed(() => productId.value === 'new')
const product = computed(() => isNewProduct.value ? undefined : getProductById(productId.value))
const isSavingProduct = ref(false)
const deleteConfirmation = ref('')
const isDeletingProduct = ref(false)
const productTabs = ['general', 'members-area', 'settings', 'checkout-builder', 'coproductions', 'affiliates', 'links'] as const
type ProductTab = typeof productTabs[number]
const activeProductTab = computed<ProductTab>(() => {
  const tab = String(route.query.tab || 'general')
  return productTabs.includes(tab as ProductTab) ? tab as ProductTab : 'general'
})
const tabPath = (tab: ProductTab) => `/products/edit/${productId.value}?tab=${tab}`
const tabClass = (tab: ProductTab) => [
  'py-1 font-medium static text-sm leading-5 rounded-md cursor-pointer px-3 transition-colors',
  activeProductTab.value === tab ? 'text-indigo-700 bg-indigo-100' : 'text-gray-600 hover:text-gray-700 focus:outline-none'
]
const selectProductTab = (event: Event) => {
  const tab = (event.target as HTMLSelectElement).value as ProductTab
  navigateTo(tabPath(tab))
}
const canDeleteProduct = computed(() => deleteConfirmation.value.trim() === 'EXCLUIR')
const findDeleteProductModalWrapper = () => {
  const headings = Array.from(document.querySelectorAll<HTMLElement>('[id="modal-headline"]'))
  const heading = headings.find((node) => node.textContent?.trim().toLowerCase().includes('excluir esse produto'))
  return heading?.closest<HTMLElement>('.fixed') || null
}
const openDeleteProductModal = async () => {
  deleteConfirmation.value = ''
  await nextTick()
  const wrapper = findDeleteProductModalWrapper()
  if (wrapper) wrapper.style.display = 'flex'
}
const closeDeleteProductModal = () => {
  const wrapper = findDeleteProductModalWrapper()
  if (wrapper) wrapper.style.display = 'none'
}
const confirmDeleteProduct = async () => {
  if (!canDeleteProduct.value || isDeletingProduct.value) return
  isDeletingProduct.value = true
  try {
    await deleteProduct(productId.value)
    closeDeleteProductModal()
    await navigateTo('/products')
  } finally {
    isDeletingProduct.value = false
  }
}
const parseMoneyInput = (value = '') => {
  if (!value.trim()) return ''
  const numeric = Number(value.replace(/[^\d,.-]/g, '').replace('.', '').replace(',', '.')) || 0
  return `R$ ${numeric.toFixed(2).replace('.', ',')}`
}
const readGeneralForm = () => {
  const general = document.querySelector<HTMLElement>('#general')
  const inputs = Array.from(general?.querySelectorAll<HTMLInputElement>('input') || [])
  const textInputs = inputs.filter((input) => ['text', 'tel'].includes(input.type))
  const name = textInputs[0]?.value || product.value?.name || 'Novo produto'
  const description = general?.querySelector<HTMLTextAreaElement>('textarea')?.value || product.value?.description || ''
  const priceInput = general?.querySelector<HTMLInputElement>('.v-money')
  const currency = priceInput?.parentElement?.querySelector<HTMLSelectElement>('select')?.value || product.value?.currency || 'BRL'
  const price = parseMoneyInput(priceInput?.value || product.value?.price || '')

  return {
    name,
    description,
    price,
    currency
  }
}
const readSettingsForm = () => {
  const settings = document.querySelector<HTMLElement>('#settings')
  const paymentMethod = settings?.querySelector<HTMLSelectElement>('[data-setting="payment-method"]')?.value || '3'
  const installments = Number(settings?.querySelector<HTMLSelectElement>('[data-setting="installments"]')?.value || 12) || 12
  const boletoValidityDays = Number(settings?.querySelector<HTMLInputElement>('[data-setting="boleto-validity-days"]')?.value || 3) || 3

  return {
    paymentMethod,
    paymentMethods: paymentMethodsFromSetting(paymentMethod),
    installments,
    cardStatement: settings?.querySelector<HTMLInputElement>('[data-setting="card-statement"]')?.value || undefined,
    boletoValidityDays,
    twoCardsEnabled: Boolean(productEditToggleState['Habilitar pagamento com 2 cartões']),
    cardPixEnabled: Boolean(productEditToggleState['Habilitar pagamento com Cartão + Pix']),
    smartInstallmentsEnabled: Boolean(productEditToggleState['Habilitar parcelamento inteligente']),
    repeatEmailEnabled: Boolean(productEditToggleState['Pedir para o comprador repetir o e-mail']),
    collectAddressEnabled: Boolean(productEditToggleState['Coletar o endereço do comprador']),
    collectInstagramEnabled: Boolean(productEditToggleState['Coletar o Instagram do comprador']),
    autoCurrencyEnabled: Boolean(productEditToggleState['Conversão automática de moedas (recomendado)'])
  }
}
const hydrateProductForm = async () => {
  await nextTick()
  const current = product.value
  if (!current) return

  const general = document.querySelector<HTMLElement>('#general')
  const inputs = Array.from(general?.querySelectorAll<HTMLInputElement>('input') || [])
  const textInputs = inputs.filter((input) => ['text', 'tel'].includes(input.type))
  if (textInputs[0] && !textInputs[0].value) textInputs[0].value = current.name || ''
  const description = general?.querySelector<HTMLTextAreaElement>('textarea')
  if (description && !description.value) description.value = current.description || ''
  const price = general?.querySelector<HTMLInputElement>('.v-money')
  if (price && !price.value) price.value = current.price?.replace('R$ ', '') || ''
  const image = general?.querySelector<HTMLImageElement>('img.w-48')
  if (image && current.imageUrl) {
    image.src = current.imageUrl
    image.alt = current.imageUrl
  }

  const settings = document.querySelector<HTMLElement>('#settings')
  const productSettings = current.settings
  if (settings && productSettings) {
    const paymentMethod = settings.querySelector<HTMLSelectElement>('[data-setting="payment-method"]')
    if (paymentMethod) paymentMethod.value = productSettings.paymentMethod || '3'
    const installments = settings.querySelector<HTMLSelectElement>('[data-setting="installments"]')
    if (installments) installments.value = String(productSettings.installments || 12)
    const cardStatement = settings.querySelector<HTMLInputElement>('[data-setting="card-statement"]')
    if (cardStatement && !cardStatement.value) cardStatement.value = productSettings.cardStatement || ''
    const boletoValidityDays = settings.querySelector<HTMLInputElement>('[data-setting="boleto-validity-days"]')
    if (boletoValidityDays && !boletoValidityDays.value) boletoValidityDays.value = String(productSettings.boletoValidityDays || 3)

    productEditToggleState['Habilitar pagamento com 2 cartões'] = Boolean(productSettings.twoCardsEnabled)
    productEditToggleState['Habilitar pagamento com Cartão + Pix'] = Boolean(productSettings.cardPixEnabled)
    productEditToggleState['Habilitar parcelamento inteligente'] = Boolean(productSettings.smartInstallmentsEnabled)
    productEditToggleState['Pedir para o comprador repetir o e-mail'] = productSettings.repeatEmailEnabled ?? true
    productEditToggleState['Coletar o endereço do comprador'] = Boolean(productSettings.collectAddressEnabled)
    productEditToggleState['Coletar o Instagram do comprador'] = Boolean(productSettings.collectInstagramEnabled)
    productEditToggleState['Conversão automática de moedas (recomendado)'] = Boolean(productSettings.autoCurrencyEnabled)
    await applyProductEditToggleState()
  }
}
const saveProduct = async () => {
  if (isSavingProduct.value) return
  isSavingProduct.value = true

  try {
    const general = readGeneralForm()
    const hasImageOverride = Object.prototype.hasOwnProperty.call(complexFieldState.files, 'product-image')
    let imageUrl = hasImageOverride ? complexFieldState.files['product-image'] : product.value?.imageUrl
    const imageFile = complexFieldState.fileObjects['product-image']
    let targetProductId = productId.value

    if (isNewProduct.value) {
      const created = await createProduct({
        ...general,
        imageUrl,
        status: 'Rascunho',
        type: 'Produto digital'
      })
      targetProductId = created.id
    }

    if (imageFile) {
      const extension = imageFile.name.split('.').pop() || 'png'
      const uploaded = await uploadFile('product-images', `${targetProductId}/cover.${extension}`, imageFile)
      if (uploaded.data?.publicUrl) imageUrl = uploaded.data.publicUrl
    }

    await updateProduct(targetProductId, {
      ...general,
      imageUrl,
      settings: readSettingsForm()
    })
    if (isNewProduct.value) {
      await navigateTo(`/products/edit/${targetProductId}?tab=${activeProductTab.value}`, { replace: true })
    }
    await hydrateProductForm()
    showSuccessToast('As alterações do produto foram salvas')
  } finally {
    isSavingProduct.value = false
  }
}
watch([product, activeProductTab], hydrateProductForm, { flush: 'post' })
watch(productId, (id) => {
  if (id === 'new') {
    delete complexFieldState.files['product-image']
    delete complexFieldState.fileObjects['product-image']
  }
}, { immediate: true })
onMounted(hydrateProductForm)
</script>

